VALUES
  ('aviation-1dfb84e5-moex-00086', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-7bf35b0f', 'sub-aviation-1dfb84e5-06', NULL, 'single_choice', '我國憲法第129條明定，憲法所規定之各種選舉，以普通、平等、直接及無記名投票之方法行之。有 關選舉原則，下列敘述何者錯誤？', '["縣市議會議長及副議長之選舉及罷免，自應受本條拘束", "憲法明文規定婦女保障名額制度，仍無違平等原則之要求", "公職人員選舉罷免法處罰選舉人之亮票行為，是為貫徹秘密投票原則", "中華民國國民年滿20歲者有依法選舉之權，是普通原則的具體展現"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00087', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-7bf35b0f', 'sub-aviation-1dfb84e5-06', NULL, 'single_choice', '公務人員週休二日實施辦法第4條第1項規定：「交通運輸、警察、消防、海岸巡防、醫療、關務等機 關（構），為全年無休服務民眾，應實施輪班、輪休制度。」可能對下列何種基本權利構成侵害？', '["訴訟權", "健康權", "人身自由權", "應考試權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00088', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-7bf35b0f', 'sub-aviation-1dfb84e5-06', NULL, 'single_choice', '依司法院釋字第791號解釋，下列敘述何者錯誤？', '["以刑罰制裁通姦及相姦行為，其目的在於約束配偶雙方履行婚姻忠誠義務，以維護婚姻制度及個別 婚姻之存續，洵屬正當", "有配偶而與人通姦者，處1年以下有期徒刑之規定，涉及憲法第22條保障之性自主權", "刑法通姦罪規定對性自主權之限制是否合於比例原則，應受較嚴格之審查", "對配偶撤回通姦罪告訴，其效力不及於相姦人之規定，與憲法第7條平等權之意旨並無違背"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00089', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-7bf35b0f', 'sub-aviation-1dfb84e5-06', NULL, 'single_choice', '依司法院大法官解釋之意旨，下列何者屬於對人民職業選擇自由之主觀限制？', '["非視障者不得從事按摩業", "藥師僅得於單一處所執業", "具有博士學位者始得擔任助理教授", "限制同一區域內有線電視系統業者之經營總數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00090', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-7bf35b0f', 'sub-aviation-1dfb84e5-06', NULL, 'single_choice', '依憲法及增修條文規定，課予國家負有保護義務應特別照顧、扶持及保障之對象，不包括下列何者？', '["婦女", "軍人", "外國人", "童工"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00091', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-7bf35b0f', 'sub-aviation-1dfb84e5-06', NULL, 'single_choice', '依現行規定，有關國家重要事項之決策權，下列敘述何者錯誤？', '["立法院有議決之權，但行政院無法透過覆議制度推翻", "行政院院長或部會首長應提出報告並備質詢，惟立法院得議決是否聽取報告", "若行政院院長報告並備質詢後，立法院仍議決不予支持，行政院院長得自行辭職以示負責", "若涉及法律修正，應該由行政院向立法院提出法律修正案，由立法院審議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00092', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-7bf35b0f', 'sub-aviation-1dfb84e5-06', NULL, 'single_choice', '依現行規定，下列有關監察院之敘述何者正確？', '["監察委員在院內所為之言論及表決，對院外不負責任", "監察委員，除現行犯外，非經監察院許可，不得逮捕或拘禁", "監察委員不得兼任其他公職或執行業務", "監察院設審計長，審計長應於行政院提出決算後3個月內，依法完成其審核，並提出審核報告於監察院"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00093', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-7bf35b0f', 'sub-aviation-1dfb84e5-06', NULL, 'single_choice', '關於司法院大法官，下列敘述何者錯誤？', '["司法院大法官有統一解釋法令及解釋憲法之權限", "大法官由總統提名，經立法院同意任命之", "大法官除法官轉任者外，不適用法官終身職待遇之規定", "司法院院長享有8年任期之保障"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00094', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-7bf35b0f', 'sub-aviation-1dfb84e5-06', NULL, 'single_choice', '依憲法訴訟法之規定，關於「國家機關聲請法規範違憲」之「聲請人」，下列敘述何者錯誤？', '["中央選舉委員會於其獨立行使職權之範圍內，可以作為聲請人", "臺北市政府就委辦事項的範圍內，應報請行政院，由行政院作為聲請人", "總統府作為國家最高機關，可以作為聲請人", "考試院就其作為考試事項的國家最高機關，可以作為聲請人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00095', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-7bf35b0f', 'sub-aviation-1dfb84e5-06', NULL, 'single_choice', '電子遊戲場業管理條例第9條第1項規定「電子遊戲場業營業場所應距離國民中、小學、高中、職校、 醫院50公尺以上。」依司法院大法官解釋，下列敘述何者錯誤？', '["上述距離限制，係對從事工作地點之執行職業自由之限制", "上開規定係保留地方因地制宜空間所設之最低標準，故直轄市、縣（市）得另以自治條例為應保持 更長距離之規範", "各直轄市、縣（市）基於因地制宜政策考量而以自治條例設定較長之距離規定，係屬必要之手段", "直轄市、縣（市）自治條例之距離限制規定，如超出法定最低限制較多時，縱使可能產生實質阻絕 之效果，亦不違反比例原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL)
